1	export type Cell = { x: number; y: number };
2	
3	const isNeighbor = (a: Cell, b: Cell): boolean =>
4	  Math.abs(a.x - b.x) <= 1 &&
5	  Math.abs(a.y - b.y) <= 1 &&
6	  (a.x !== b.x || a.y !== b.y);
7	
8	const countNeighbors = (cell: Cell, liveCells: Cell[]): number =>
9	  liveCells.filter((candidate) => isNeighbor(cell, candidate)).length;
10	
11	const cellEquals = (a: Cell, b: Cell): boolean => a.x === b.x && a.y === b.y;
12	
13	const includesCell = (cells: Cell[], target: Cell): boolean =>
14	  cells.some((c) => cellEquals(c, target));
15	
16	const getCandidateDeadCells = (liveCells: Cell[]): Cell[] => {
17	  const candidates: Cell[] = [];
18	  for (const cell of liveCells) {
19	    for (let dx = -1; dx <= 1; dx++) {
20	      for (let dy = -1; dy <= 1; dy++) {
21	        if (dx === 0 && dy === 0) continue;
22	        const candidate = { x: cell.x + dx, y: cell.y + dy };
23	        if (!includesCell(liveCells, candidate) && !includesCell(candidates, candidate)) {
24	          candidates.push(candidate);
25	        }
26	      }
27	    }
28	  }
29	  return candidates;
30	};
31	
32	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
33	  const survivors = liveCells.filter((cell) => {
34	    const neighbors = countNeighbors(cell, liveCells);
35	    return neighbors === 2 || neighbors === 3;
36	  });
37	
38	  const newborns = getCandidateDeadCells(liveCells).filter(
39	    (cell) => countNeighbors(cell, liveCells) === 3
40	  );
41	
42	  return [...survivors, ...newborns];
43	};
